import React from 'react';
import { Box, Users, Trash2, Clock, AlertTriangle } from 'lucide-react';

const ListaOfertas = ({ ofertas, onDelete }) => {
  if (ofertas.length === 0) return <div style={emptyStateStyle}><p>No hay ofertas activas.</p></div>;

  // Función para calcular tiempo restante
  const getTiempoRestante = (fechaVence) => {
    const ahora = new Date();
    const vence = new Date(fechaVence);
    const dif = vence - ahora;
    
    if (dif <= 0) return "Expirado";
    
    const horas = Math.floor(dif / (1000 * 60 * 60));
    if (horas > 24) return `Vence en ${Math.floor(horas / 24)} días`;
    return `Vence en ${horas}hs`;
  };

  return (
    <div style={gridStyle}>
      {ofertas.map((o) => {
        const ahorro = Math.round(((o.precioViejo - o.precioNuevo) / o.precioViejo) * 100);
        const esStockCritico = o.stock <= 5;
        const tiempoRestante = getTiempoRestante(o.fechaVencimiento);

        return (
          <div key={o.id} style={cardStyle}>
            {/* Imagen y Badge de Ahorro */}
            <div style={imageWrapper}>
              <img src={o.imagen} alt={o.producto} style={imgStyle} />
              <div style={ahorroBadge}>-{ahorro}% OFF</div>
              {esStockCritico && (
                <div style={stockCriticoBadge}>
                  <AlertTriangle size={12} /> ¡ÚLTIMAS UNIDADES!
                </div>
              )}
            </div>

            <div style={{ padding: '15px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <h3 style={{ margin: '0 0 10px 0', fontSize: '1.1rem', color: '#1e293b' }}>{o.producto}</h3>
              </div>
              
              <div style={{ display: 'flex', alignItems: 'baseline', gap: '10px', marginBottom: '10px' }}>
                <span style={precioNuevoStyle}>${o.precioNuevo}</span>
                <span style={precioViejoStyle}>${o.precioViejo}</span>
              </div>

              {/* Fecha de Vencimiento */}
              <div style={vencimientoStyle(tiempoRestante === "Expirado")}>
                <Clock size={14} />
                <span>{tiempoRestante === "Expirado" ? "Oferta Finalizada" : tiempoRestante}</span>
              </div>

              <div style={divider} />

              {/* Stats: Stock y Límite */}
              <div style={statsContainer}>
                <div style={{...statItem, color: esStockCritico ? '#e11d48' : '#64748b'}}>
                  <Box size={14} /> 
                  <span>Stock: <strong style={{fontSize: '0.9rem'}}>{o.stock}</strong></span>
                </div>
                <div style={statItem}>
                  <Users size={14} /> 
                  <span>Límite: <strong>{o.limitePorCliente || '∞'}</strong></span>
                </div>
              </div>

              <button onClick={() => onDelete(o.id)} style={btnDelete}>
                <Trash2 size={14} /> Eliminar Oferta
              </button>
            </div>
          </div>
        );
      })}
    </div>
  );
};

/* --- ESTILOS MEJORADOS --- */
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '25px' };
const cardStyle = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', transition: 'transform 0.2s', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const imageWrapper = { height: '160px', position: 'relative', background: '#f1f5f9' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };

const ahorroBadge = { position: 'absolute', top: '10px', right: '10px', background: '#22c55e', color: 'white', padding: '5px 10px', borderRadius: '10px', fontSize: '0.75rem', fontWeight: 'bold' };
const stockCriticoBadge = { position: 'absolute', bottom: '10px', left: '10px', background: '#e11d48', color: 'white', padding: '4px 8px', borderRadius: '6px', fontSize: '0.65rem', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '4px' };

const precioNuevoStyle = { fontSize: '1.6rem', fontWeight: '900', color: '#1e293b' };
const precioViejoStyle = { fontSize: '1rem', textDecoration: 'line-through', color: '#94a3b8' };

const vencimientoStyle = (expirado) => ({
  display: 'flex',
  alignItems: 'center',
  gap: '6px',
  fontSize: '0.8rem',
  color: expirado ? '#e11d48' : '#e67e22',
  background: expirado ? '#fff1f2' : '#fff7ed',
  padding: '6px 10px',
  borderRadius: '8px',
  fontWeight: '600'
});

const divider = { height: '1px', background: '#f1f5f9', margin: '15px 0' };
const statsContainer = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' };
const statItem = { display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.8rem' };
const btnDelete = { width: '100%', padding: '10px', background: '#f8fafc', color: '#64748b', border: '1px solid #e2e8f0', borderRadius: '12px', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' };
const emptyStateStyle = { textAlign: 'center', padding: '60px', color: '#94a3b8', background: 'white', borderRadius: '20px' };

export default ListaOfertas;
